         _words = text.Split((char[]?)null, StringSplitOptions.RemoveEmptyEntries);

         int[] lengths = new int[_words.Length];
         for (int i = 0; i < _words.Length; i++)
             lengths[i] = _words[i].Length;
         _wordLengths = new ReadOnlyCollection<int>(lengths);
     }

